import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Trash2, Edit, ArrowLeft, X, Save, 
  Loader2, Search, CheckCircle2, Box, Send, Clock, Weight, Upload, ImageIcon, Table as TableIcon
} from 'lucide-react';

import GestionInventario from './GestionInventario'; 

// --- COMPONENTE 1: EL CARGADOR TIPO EXCEL ---
const CargadorMasivoPro = ({ onClose, cloudName, folder, preset, localId, onComplete, API_URL }) => {
  const [items, setItems] = useState([]); 
  const [subiendo, setSubiendo] = useState(false);

  const handleFileChange = (e) => {
    const nuevosArchivos = Array.from(e.target.files).map(file => ({
      file,
      preview: URL.createObjectURL(file),
      tipo: '',
      marca: '',
      contenido: '',
      precio: '',
      stock: '',
      peso: '',
      subido: false,
      error: false
    }));
    setItems([...items, ...nuevosArchivos]);
  };

  const updateItem = (index, field, value) => {
    const newItems = [...items];
    newItems[index][field] = value;
    setItems(newItems);
  };

  const procesarCarga = async () => {
    if (items.some(i => !i.tipo || !i.precio)) {
      alert("Por favor completa Tipo y Precio de todos los productos antes de subir.");
      return;
    }
    
    setSubiendo(true);
    for (let i = 0; i < items.length; i++) {
      if (items[i].subido) continue;

      const formData = new FormData();
      formData.append('file', items[i].file);
      formData.append('upload_preset', preset);
      formData.append('folder', folder);

      try {
        // 1. Subir a Cloudinary
        const resCloud = await axios.post(
          `https://api.cloudinary.com/v1_1/${cloudName}/image/upload`,
          formData
        );

        // 2. Crear producto en BD con el public_id REAL devuelto por la nube
        const nuevoProducto = {
          producto: `${items[i].tipo} ${items[i].marca} ${items[i].contenido}`.trim(),
          publicId: resCloud.data.public_id, // Guardamos el path completo
          local: localId,
          precioNuevo: Number(items[i].precio),
          precioViejo: Number(items[i].precio),
          stock: Number(items[i].stock) || 0,
          peso: Number(items[i].peso) || 0,
          publicado: false,
          categoria: 'Almacén'
        };

        await axios.post(`${API_URL}/api/ofertas`, nuevoProducto);
        
        const newItems = [...items];
        newItems[i].subido = true;
        setItems([...newItems]);
      } catch (err) {
        console.error("Error en fila " + i, err);
        const newItems = [...items];
        newItems[i].error = true;
        setItems([...newItems]);
      }
    }
    setSubiendo(false);
    onComplete(); // Recarga la lista principal
  };

  return (
    <div style={modalOverlay}>
      <div style={{...modalContent, width: '95%', maxWidth: '1100px', maxHeight: '90vh', display: 'flex', flexDirection: 'column'}}>
        <div style={modalHeader}>
          <div style={{display:'flex', alignItems:'center', gap:10}}>
            <TableIcon size={24} color="#8b5cf6"/>
            <h3 style={titleStyle}>Carga Inteligente de Inventario</h3>
          </div>
          <button onClick={onClose} style={closeBtn}><X /></button>
        </div>

        <div style={{padding: '0 20px 20px', flex: 1, overflowY: 'auto'}}>
          <div style={{display:'flex', gap: 10, marginBottom: 20}}>
            <input type="file" multiple accept="image/*" onChange={handleFileChange} id="bulk-pro" style={{display:'none'}} />
            <label htmlFor="bulk-pro" style={btnPlus}>
              <Plus size={18}/> Seleccionar Fotos
            </label>
            <p style={subtitleStyle}>Paso: Elige las fotos y completa los datos a la derecha.</p>
          </div>

          <table style={excelTable}>
            <thead>
              <tr style={excelThRow}>
                <th>Foto</th>
                <th>Producto / Tipo</th>
                <th>Marca</th>
                <th>Contenido</th>
                <th>Precio $</th>
                <th>Stock</th>
                <th>Peso kg</th>
                <th>Estado</th>
              </tr>
            </thead>
            <tbody>
              {items.map((item, idx) => (
                <tr key={idx} style={item.subido ? {background: '#f0fdf4'} : {}}>
                  <td style={excelTd}><img src={item.preview} style={tableImg} alt="prev" /></td>
                  <td style={excelTd}><input style={tableInput} placeholder="Ej: Aceite" value={item.tipo} onChange={e => updateItem(idx, 'tipo', e.target.value)} disabled={item.subido}/></td>
                  <td style={excelTd}><input style={tableInput} placeholder="Ej: Natura" value={item.marca} onChange={e => updateItem(idx, 'marca', e.target.value)} disabled={item.subido}/></td>
                  <td style={excelTd}><input style={tableInput} placeholder="Ej: 900ml" value={item.contenido} onChange={e => updateItem(idx, 'contenido', e.target.value)} disabled={item.subido}/></td>
                  <td style={excelTd}><input style={tableInput} type="number" placeholder="0" value={item.precio} onChange={e => updateItem(idx, 'precio', e.target.value)} disabled={item.subido}/></td>
                  <td style={excelTd}><input style={tableInput} type="number" placeholder="0" value={item.stock} onChange={e => updateItem(idx, 'stock', e.target.value)} disabled={item.subido}/></td>
                  <td style={excelTd}><input style={tableInput} type="number" placeholder="0" value={item.peso} onChange={e => updateItem(idx, 'peso', e.target.value)} disabled={item.subido}/></td>
                  <td style={{...excelTd, textAlign:'center'}}>
                    {item.subido ? <CheckCircle2 color="#10b981" size={20}/> : item.error ? <X color="#ef4444" size={20}/> : <Clock color="#94a3b8" size={20}/>}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div style={footerCargador}>
          <button onClick={onClose} style={btnBack}>Cancelar</button>
          <button onClick={procesarCarga} disabled={subiendo || items.length === 0} style={{...btnSave, width: '280px'}}>
            {subiendo ? <Loader2 className="animate-spin" size={18} /> : <Send size={18} />}
            {subiendo ? 'Procesando Productos...' : 'Vincular y Subir Todo'}
          </button>
        </div>
      </div>
    </div>
  );
};

// --- COMPONENTE 2: PANEL PRINCIPAL ---
const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();
  const [ofertas, setOfertas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showCargador, setShowCargador] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");

  const CLOUD_NAME = "dwpgncjgn";
  const CARPETA_NUEVA = "PRODUCTOS"; 
  const PRESET_NAME = "PRODUCTOS"; 
  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  const cargarOfertas = useCallback(async () => {
    if (!localId) return;
    setLoading(true);
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setOfertas(res.data);
    } catch (e) { console.error(e); } finally { setLoading(false); }
  }, [localId, API_URL]);

  useEffect(() => { cargarOfertas(); }, [cargarOfertas]);

  const ofertasFiltradas = useMemo(() => {
    return ofertas.filter(o => o.producto.toLowerCase().includes(searchTerm.toLowerCase()));
  }, [ofertas, searchTerm]);

  return (
    <div style={containerStyle}>
      <div style={topBar}>
        <button onClick={() => navigate('/dashboard')} style={btnBack}><ArrowLeft size={18}/> Volver</button>
        <div style={badgeLocal}>Local ID: {localId?.slice(-6)}</div>
      </div>

      <div style={headerStyle}>
        <div>
          <h1 style={titleStyle}>Gestión de Productos</h1>
          <p style={subtitleStyle}>Usa la carga masiva para asociar fotos y datos rápidamente.</p>
        </div>
        <button onClick={() => setShowCargador(true)} style={btnCloud}>
          <TableIcon size={20}/> CARGA MASIVA TIPO EXCEL
        </button>
      </div>

      <div style={searchBarContainer}>
        <Search size={20} color="#94a3b8" style={searchIcon} />
        <input style={searchInput} placeholder="Buscar producto en tu inventario..." onChange={e => setSearchTerm(e.target.value)} />
      </div>

      <div style={gridStyle}>
        {loading ? <div style={{gridColumn:'1/-1', textAlign:'center'}}><Loader2 className="animate-spin" size={40}/></div> : 
          ofertasFiltradas.map(o => (
          <div key={o._id} style={itemCard}>
            <div style={imageContainerStyle}>
              <img 
                src={o.publicId.startsWith('http') ? o.publicId : `https://res.cloudinary.com/${CLOUD_NAME}/image/upload/f_auto,q_auto/v1/${o.publicId}`} 
                alt={o.producto}
                style={imageStyle}
                onError={(e) => {
                  e.target.onerror = null;
                  e.target.src = 'https://placehold.co/200x200/f1f5f9/64748b?text=Sin+Foto';
                }}
              />
            </div>
            <h4 style={prodName}>{o.producto}</h4>
            <div style={priceContainer}>
              <span style={currentPrice}>${o.precioNuevo}</span>
              <div style={badgeStockIn}>Stock: {o.stock}</div>
            </div>
            <button style={btnDeleteMini} onClick={async () => {
                if(window.confirm("¿Eliminar?")) { await axios.delete(`${API_URL}/api/ofertas/${o._id}`); cargarOfertas(); }
            }}> <Trash2 size={14}/> Eliminar </button>
          </div>
        ))}
      </div>

      {showCargador && (
        <CargadorMasivoPro 
          cloudName={CLOUD_NAME} 
          folder={CARPETA_NUEVA} 
          preset={PRESET_NAME} 
          localId={localId}
          API_URL={API_URL}
          onComplete={cargarOfertas}
          onClose={() => setShowCargador(false)} 
        />
      )}
    </div>
  );
};

